class Program
{
    static void Main()
    {
        int count = 42;
        long big = 2_000_000_000L;
        double pi = 3.14159;
        bool found = true;
        string name = "Alice";
        Console.WriteLine(count);   // 42
        Console.WriteLine(big);     // 2000000000
        Console.WriteLine(pi);      // 3.14159
        Console.WriteLine(found);   // True
        Console.WriteLine(name);    // Alice
    }
}

