class Program
{
    static void Main()
    {
        int a = 7, b = 2;
        Console.WriteLine(a / b);            // 3 (integer division)
        Console.WriteLine((double)a / b);    // 3.5

        double x = 9.99;
        int truncated = (int)x;
        Console.WriteLine(truncated);        // 9

        string s = "123";
        int parsed = int.Parse(s);
        Console.WriteLine(parsed + 1);       // 124
    }
}

