class Program
{
    static void Main()
    {
        int? maybeNum = null;
        Console.WriteLine(maybeNum.HasValue);  // False

        maybeNum = 42;
        Console.WriteLine(maybeNum.Value);     // 42

        int? empty = null;
        int safe = empty ?? -1;
        Console.WriteLine(safe);               // -1

        string name = null;
        Console.WriteLine(name?.Length ?? 0);  // 0
    }
}

